#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    string s, t;
    cin >> s >> t;
    unordered_map<char, char> s_to_t;
    unordered_map<char, char> t_to_s;
    for(int i = 0; i < n; i++){
        if(s_to_t.find(s[i]) == s_to_t.end() && t_to_s.find(t[i]) == t_to_s.end()){
            s_to_t[s[i]] = t[i];
            t_to_s[t[i]] = s[i];
        } else if(s_to_t[s[i]] != t[i] || t_to_s[t[i]] != s[i]){
            cout << "false" << endl;
            return 0;
        }
    }
    cout << "true" << endl;
    return 0;
}
